sql:
SELECT COUNT(experiment_id) AS total_experiments
FROM experiment_data_splits
WHERE split_id = 1;

external_knowledge:
; The term 'top 3 experiments' means the experiments with the three highest incumbent validation metrics within each project; 
; The validation metric is a measure used to evaluate the performance of the experiment; 
; The ranking of the experiments is determined by the incumbent validation metric in descending order.
